# OEIS sequence: A056056

from math import prod
from sympy.ntheory.factor_ import digits
from sympy import primerange
def A056056(n):
    m = n>>1
    def s(n,p): return sum(digits(n,p)[1:])
    return prod(p**((s(m,p)+s(n-m,p)-s(n,p))//(p-1)>>1) for p in primerange(n+1)) # _Chai Wah Wu_, May 05 2026

